mapper.update:
UPDATE ds_wallet
SET balance = balance - #{amount},
    frozen_balance = frozen_balance + #{amount},
    version = version + 1,
    balance_hash = #{balanceHash},
    update_time = CURRENT_TIMESTAMP
WHERE wallet_no = #{walletNo}
  AND version = #{version}
  AND balance >= #{amount}
  AND status = 'ACTIVE'

UPDATE ds_wallet
SET frozen_balance = frozen_balance - #{amount},
    balance = balance + #{amount},
    version = version + 1,
    balance_hash = #{balanceHash},
    update_time = CURRENT_TIMESTAMP
WHERE wallet_no = #{walletNo}
  AND version = #{version}
  AND frozen_balance >= #{amount}
  AND status = 'ACTIVE'

UPDATE ds_wallet
SET status = #{status},
    version = version + 1,
    update_time = CURRENT_TIMESTAMP
WHERE wallet_no = #{walletNo}
  AND version = #{version}

